            <div ref={scannerRef}>
              <Scanner user={user} />
            </div>
            <WasteCategories />
            <div ref={aboutRef}>
              <About />
            </div>
            {!user && <Impact onSignUpClick={() => navigateTo('register')} />}
            <Tips />
          </>
        )}
        {currentView === 'login' && (
          <Login 
            onToggleAuth={() => navigateTo('register')} 
            onBackHome={() => navigateTo('landing')}
            onSuccess={handleAuthSuccess}
          />
        )}
        {currentView === 'register' && (
          <Register 
            onToggleAuth={() => navigateTo('login')} 
            onBackHome={() => navigateTo('landing')}
